{
  "outline": [
    {
      "section": "Introduction",
      "content": "Welcome to the AI-Powered Social Media Post Generator Prompt Pack. This guide provides effective prompts to generate diverse and engaging social media content using AI models like GPT-3/4."
    },
    {
      "section": "How to Use These Prompts",
      "content": "For best results, provide context about your brand, target audience, and desired outcome. Experiment with prompt variations."
    },
    {
      "section": "Prompt Categories",
      "subsections": [
        {
          "title": "Engagement Prompts",
          "description": "Designed to spark conversations and encourage audience interaction.",
          "prompts": [
            "Generate a thought-provoking question about [industry topic] for LinkedIn.",
            "Create an engaging poll for Instagram Stories related to [product/service].",
            "Draft a 'caption this' post for Facebook using the image of [describe image].",
            "Write a fun Twitter thread starter about [common pain point]."
          ]
        },
        {
          "title": "Promotional Prompts",
          "description": "Focuses on highlighting products, services, or special offers.",
          "prompts": [
            "Craft a persuasive Instagram caption announcing a [discount]% off sale on [product].",
            "Write a short, attention-grabbing ad copy for Facebook promoting our new [service].",
            "Develop a LinkedIn post highlighting the benefits of our [product feature].",
            "Create a teaser tweet for an upcoming [event/launch]."
          ]
        },
        {
          "title": "Educational/Informative Prompts",
          "description": "Aims to provide value and establish expertise.",
          "prompts": [
            "Generate a quick tip about [skill/topic] for Twitter.",
            "Write a concise explanation of [complex concept] for a Facebook post.",
            "Develop an Instagram carousel post outline on '[how-to] for [target audience]'.",
            "Create a LinkedIn article idea about industry trends in [niche]."
          ]
        }
      ]
    },
    {
      "section": "Tone and Style Variations",
      "content": "Modify prompts to achieve specific tones: humorous, professional, urgent, empathetic, inspirational."
    },
    {
      "section": "Platform-Specific Optimization Tips",
      "content": "Consider character limits, hashtag usage, and optimal content formats for each platform."
    }
  ]
}

